(() => {
  const zone = 'America/Sao_Paulo';
  const now = $now.setZone(zone);
  const startHour = 9;
  const endHour = 18;

  // Soma 20 horas ao horário atual
  let targetTime = now.plus({ hours: 20 });

  // Se a hora resultante ultrapassar o horário comercial do dia
  if (targetTime.hour >= endHour || targetTime.hour < startHour) {
    // Limita para o fim do horário comercial (18h) do dia
    targetTime = targetTime.set({ hour: endHour, minute: 0, second: 0, millisecond: 0 });

    // Se já passou de 18h hoje, vai para 18h de hoje mesmo
    if (now.hour >= endHour) {
      targetTime = now.set({ hour: endHour, minute: 0, second: 0, millisecond: 0 });
    }
  }

  // Ajusta para dias úteis (se cair no fim de semana)
  if (targetTime.weekday === 6) { // Sábado
    targetTime = targetTime.plus({ days: 2 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
  } else if (targetTime.weekday === 7) { // Domingo
    targetTime = targetTime.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
  }

  return targetTime.toFormat("yyyy-MM-dd HH:mm");
})()
}}

