## Follow Up antigo (8h)

{{
(() => {
  const zone = 'America/Sao_Paulo';
  const now = $now.setZone(zone);
  const startHour = 9;
  const endHour = 18;

  if (now.hour >= startHour && now.hour < endHour) {
    return now.plus({ hours: 8 }).toFormat("yyyy-MM-dd HH:mm");
  }

  if (now.hour < startHour) {
    return now.set({ hour: startHour, minute: 0, second: 0, millisecond: 0 })
              .toFormat("yyyy-MM-dd HH:mm");
  }

  return now.plus({ days: 1 })
            .set({ hour: startHour, minute: 0, second: 0, millisecond: 0 })
            .toFormat("yyyy-MM-dd HH:mm");
})()
}}

