const messages = $input.first().json.payload;

// Filtra apenas mensagens incoming com conteúdo real do contato
const incomingMsgs = messages.filter(m =>
  m.message_type === 0 &&
  m.content &&
  m.content.trim() !== '' &&
  m.sender_type === 'Contact'
);

if (incomingMsgs.length === 0) {
  return [{ json: { skip: true } }];
}

// Pega a mais recente
const last = incomingMsgs.sort((a, b) => b.created_at - a.created_at)[0];

const original = $('Webhook').first().json;

// Monta um payload idêntico ao que o webhook receberia
return [{
  json: {
    body: {
      ...original.body,
      message_type: 'incoming',
      content: last.content,
      conversation: {
        ...original.body.conversation,
        messages: [{
          ...last,
          processed_message_content: last.content
        }]
      }
    }
  }
}];
